module multi_pipe_4bit #(
    parameter size = 4
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    output [2*size-1:0] mul_out
);

    reg [size-1:0] mul_a_reg [size-1:0];
    reg [size-1:0] mul_b_reg [size-1:0];
    reg [2*size-1:0] partial_products [size-1:0];
    reg [2*size-1:0] sum_registers [size-1:0];

    integer i;

    wire [size+size-1:0] mul_a_ext = {{size{1'b0}}, mul_a};
    wire [size+size-1:0] mul_b_ext = {{size{1'b0}}, mul_b};

    always @(*) begin
        for (i = 0; i < size; i = i + 1) begin
            if (mul_b_ext[i]) begin
                partial_products[i] = mul_a_ext << i;
            end else begin
                partial_products[i] = 'd0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < size; i = i + 1) begin
                sum_registers[i] <= 'd0;
            end
        end else begin
            for (i = 0; i < size; i = i + 1) begin
                if (i == 0) begin
                    sum_registers[i] <= partial_products[i];
                end else begin
                    sum_registers[i] <= sum_registers[i-1] + partial_products[i];
                end
            end
        end
    end

    assign mul_out = (rst_n) ? sum_registers[size-1] : 'd0;

endmodule
